const results = [];

for (let i = 0; i < $input.all().length; i++) {
  const input = $input.all()[i].json;
  const prev = $('Parse Email').all()[i].json;

  let category = 'FAQ', priority = 'P3', summary = '', language = 'HR';
  try {
    const content = input.content[0].text;
    const parsed = JSON.parse(content);
    category = parsed.category || 'FAQ';
    priority = parsed.priority || 'P3';
    summary = parsed.summary || '';
    language = parsed.language || 'HR';
  } catch(e) {}

  results.push({ json: { ...prev, category, priority, summary, language } });
}

return results;

// Batch all records into groups of 10 and send to Airtable
const AIRTABLE_TOKEN = process.env.AIRTABLE_TOKEN;
const AIRTABLE_URL = 'https://api.airtable.com/v0/appT9NVuu8MyFHFsj/tblHtfXkcsmWjk1aQ';

const items = $input.all();
const BATCH_SIZE = 10;
let inserted = 0;

for (let i = 0; i < items.length; i += BATCH_SIZE) {
  const batch = items.slice(i, i + BATCH_SIZE);
  const records = batch.map(item => ({
    fields: {
      Customer: item.json.customerName || '(unknown)',
      Subject: item.json.subject || '',
      Email: item.json.customerEmail || '',
      Category: item.json.category || 'FAQ',
      Priority: item.json.priority || 'P3',
      Summary: item.json.summary || '',
      'Order #': item.json.orderNum || '',
      Phone: item.json.phone || '',
      Product: item.json.product || '',
      Total: item.json.total || 0,
      Address: item.json.address || '',
      Payment: item.json.payment || '',
      Shipping: item.json.shipping || '',
      'Gmail Link': item.json.gmailLink || '',
      Received: item.json.receivedAt || new Date().toISOString(),
      'Order Status': 'New'
    }
  }));

  await this.helpers.httpRequest({
    method: 'POST',
    url: AIRTABLE_URL,
    headers: {
      'Authorization': 'Bearer ' + AIRTABLE_TOKEN,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ records })
  });

  inserted += batch.length;

  // 250ms pause between batches to respect rate limit
  if (i + BATCH_SIZE < items.length) {
    await new Promise(r => setTimeout(r, 250));
  }
}

return [{ json: { success: true, inserted } }];
